const res = $input.first().json;
const rows = res.values || [];
let found = null;
for (let i = 0; i < rows.length; i++) {
  const s = (rows[i][4] || '').toString().toUpperCase().trim();
  if (s === 'PENDING') { found = { idx: i, row: rows[i] }; break; }
}
if (!found) throw new Error('No PENDING topic in Dashboard tab. Set STATUS (col E) = PENDING for a row.');
const sheetRow   = found.idx + 4;
const topic      = (found.row[1] || '').trim();
const difficulty = (found.row[2] || 'beginner').trim();
const durationMin = parseFloat(found.row[3]) || 1;
if (!topic) throw new Error('PENDING row found but Topic (col B) is empty.');
const jobId = (found.row[0] || '').trim() || ('PHY-' + Date.now().toString().slice(-8));
console.log('Row ' + sheetRow + ' | ' + jobId + ' | ' + topic + ' | ' + durationMin + 'min');
return [{ json: { job_id: jobId, topic: topic, difficulty: difficulty, duration_min: durationMin, sheet_row: sheetRow, source: 'google_sheet' } }];

const raw       = $input.first().json;
const body      = (raw.body !== undefined) ? raw.body : raw;

let sheetData = {};
try { sheetData = $('Pick PENDING Topic').first().json; } catch(e) {}

const jobId      = body.job_id      || raw.job_id      || sheetData.job_id      || ('PHY-' + Date.now().toString().slice(-8));
const topic      = body.topic       || raw.topic       || sheetData.topic;
const sheetRow   = body.sheet_row   || raw.sheet_row   || sheetData.sheet_row   || null;
const difficulty = body.difficulty  || raw.difficulty  || sheetData.difficulty  || 'beginner';
// duration_min comes from Google Sheet col D — drives everything
const durationMin = parseFloat(body.duration_min || raw.duration_min || sheetData.duration_min) || 1;

if (!topic) throw new Error('No topic found. Add a PENDING row in Google Sheet (col B=topic, col D=duration_min, col E=PENDING).');

const durationSec = Math.round(durationMin * 60);
const numClips    = Math.max(2, Math.ceil(durationSec / 5));
const wordTarget  = Math.max(15, Math.round(durationSec * 2.5)); // ~150 wpm = 2.5 words/sec

console.log('Topic: ' + topic);
console.log('Duration: ' + durationMin + ' min (' + durationSec + 's) → ' + numClips + ' clips, ~' + wordTarget + ' words');

return [{ json: {
  job_id: jobId, topic, difficulty, sheet_row: sheetRow,
  duration_min: durationMin, duration_sec: durationSec,
  num_clips: numClips, word_target: wordTarget,
  start_time: Date.now()
}}];

const response  = $input.first().json;
const jobConfig = $('Set Job Config').first().json;

if (!response.candidates || !response.candidates[0] || !response.candidates[0].content)
  throw new Error('Gemini response empty: ' + JSON.stringify(response).slice(0, 300));

let rawText = response.candidates[0].content.parts[0].text.trim();
rawText = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();

let parsed;
try { parsed = JSON.parse(rawText); }
catch(e1) {
  const s = rawText.indexOf('{'), e = rawText.lastIndexOf('}');
  try { parsed = JSON.parse((s !== -1 && e !== -1) ? rawText.slice(s, e+1) : rawText); }
  catch(e2) { throw new Error('Failed to parse Gemini JSON: ' + rawText.slice(0, 500)); }
}

if (!parsed.narration)
  throw new Error('Response missing narration field');
if (!Array.isArray(parsed.scenes) || parsed.scenes.length === 0)
  throw new Error('Response missing scenes array');

const clip_prompts = parsed.scenes.map((s, i) => {
  if (!s.visual_prompt) throw new Error('Scene ' + (i+1) + ' missing visual_prompt');
  return s.visual_prompt;
});

const wordCount = parsed.narration.trim().split(/\s+/).length;
console.log('Duration target: ' + jobConfig.duration_min + ' min | Narration: ' + wordCount + ' words | Scenes: ' + clip_prompts.length);
parsed.scenes.forEach((s, i) => {
  console.log('Scene ' + (i+1) + ' [' + s.start_sec + '-' + s.end_sec + 's]: ' + s.visual_prompt.slice(0, 80) + '...');
});

return [{ json: {
  ...jobConfig,
  narration:   parsed.narration,
  scenes:      parsed.scenes,
  clip_prompts,
  title:    parsed.title    || jobConfig.topic,
  hashtags: parsed.hashtags || '#physics #science #shorts'
}}];

const https = require('https');
const fs    = require('fs');

const data    = $input.first().json;
const apiKey  = $env.ELEVENLABS_API_KEY;
const voiceId = $env.ELEVENLABS_VOICE_ID;
const jobId   = data.job_id;

function httpsPost(hostname, path, headers, bodyStr) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(bodyStr, 'utf-8');
    const req = https.request(
      { hostname, path, method: 'POST', headers: { ...headers, 'Content-Length': buf.length } },
      (res) => {
        const chunks = [];
        res.on('data', c => chunks.push(c));
        res.on('end', () => resolve({ status: res.statusCode, body: Buffer.concat(chunks).toString() }));
      }
    );
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

const res = await httpsPost(
  'api.elevenlabs.io',
  '/v1/text-to-speech/' + voiceId + '/with-timestamps',
  { 'Content-Type': 'application/json', 'xi-api-key': apiKey },
  JSON.stringify({
    text: data.narration,
    model_id: 'eleven_multilingual_v2',
    voice_settings: { stability: 0.5, similarity_boost: 0.75, style: 0.3, use_speaker_boost: true }
  })
);

if (res.status !== 200)
  throw new Error('ElevenLabs error ' + res.status + ': ' + res.body.slice(0, 300));

const result = JSON.parse(res.body);
const audio_base64 = result.audio_base64;

// ElevenLabs returns alignment or normalized_alignment depending on version
const alignment = result.alignment || result.normalized_alignment;
if (!alignment)
  throw new Error('ElevenLabs returned no alignment data. Keys: ' + Object.keys(result).join(', '));

// Save audio file
const inputDir = '/data/ffmpeg/input';
if (!fs.existsSync(inputDir)) fs.mkdirSync(inputDir, { recursive: true });
const audioPath = inputDir + '/' + jobId + '_narration.mp3';
fs.writeFileSync(audioPath, Buffer.from(audio_base64, 'base64'));

// ── Build word-level timing ───────────────────────────────────
const chars  = alignment.characters;
const starts = alignment.character_start_times_seconds;
const ends   = alignment.character_end_times_seconds;
if (!starts || !ends || starts.length === 0)
  throw new Error('ElevenLabs alignment missing timing arrays. alignment keys: ' + Object.keys(alignment).join(', '));
const totalDuration = ends[ends.length - 1];
console.log('Audio duration: ' + totalDuration.toFixed(2) + 's');

const words = [];
let wChars = '', wStart = null, wEnd = 0;
for (let i = 0; i < chars.length; i++) {
  if (chars[i] === ' ' || chars[i] === '\n') {
    if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });
    wChars = ''; wStart = null;
  } else {
    if (wStart === null) wStart = starts[i];
    wEnd = ends[i];
    wChars += chars[i];
  }
}
if (wChars.trim()) words.push({ text: wChars.trim(), start: wStart, end: wEnd });

// ── Better subtitles: 3 words per chunk, min 0.5s display ────
// Shorter chunks = easier to read on mobile while listening
const MIN_DISPLAY = 0.5;   // seconds a subtitle must stay on screen
const WORDS_PER_CHUNK = 3;

const chunks = [];
for (let i = 0; i < words.length; i += WORDS_PER_CHUNK) {
  const group = words.slice(i, i + WORDS_PER_CHUNK);
  let endTime  = group[group.length - 1].end + 0.15;

  // Ensure this chunk is visible for at least MIN_DISPLAY seconds
  if (endTime - group[0].start < MIN_DISPLAY)
    endTime = group[0].start + MIN_DISPLAY;

  // Avoid overlapping with the next chunk's start
  const nextStart = words[i + WORDS_PER_CHUNK] ? words[i + WORDS_PER_CHUNK].start : totalDuration;
  if (endTime > nextStart - 0.05) endTime = nextStart - 0.05;

  chunks.push({
    text:  group.map(w => w.text).join(' '),
    start: group[0].start,
    end:   endTime,
    words: group
  });
}
console.log('Subtitle chunks: ' + chunks.length + ' (3 words each, min ' + MIN_DISPLAY + 's display)');

// Save subtitle data
const subsPath = inputDir + '/' + jobId + '_subs.json';
fs.writeFileSync(subsPath, JSON.stringify(chunks));

return [{ json: {
  ...data,
  audio_path:      audioPath,
  subs_path:       subsPath,
  audio_duration:  totalDuration,
  subtitle_chunks: chunks,
  word_timings:    words,
  word_count:      words.length
}}];

const researchResp = $input.first().json;
const jobData = $('Set Job Config').first().json;
let researchText = '';
try {
  researchText = researchResp.candidates[0].content.parts[0].text || '';
} catch(e) {
  researchText = 'No research available.';
}
console.log('Research obtained: ' + researchText.slice(0, 100) + '...');
return [{ json: { ...jobData, topic_research: researchText } }];
